import { ethers } from "ethers";

const RPC_URL = process.env.RPC_URL || "https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID";
const PRIVATE_KEYS = (process.env.PRIVATE_KEYS || "0xYOUR_PRIVATE_KEY")
  .split(",")
  .map((k) => k.trim())
  .filter(Boolean);

if (!RPC_URL) {
  throw new Error("Missing RPC_URL");
}

if (!PRIVATE_KEYS.length) {
  throw new Error("At least one private key is required in PRIVATE_KEYS");
}

const provider = new ethers.JsonRpcProvider(RPC_URL);

export const wallets = PRIVATE_KEYS.map((pk) => new ethers.Wallet(pk, provider));

export function getWallet(index = 0) {
  const wallet = wallets[index];
  if (!wallet) {
    throw new Error(`Wallet not found at index ${index}`);
  }
  return wallet;
}

export async function getNativeBalance(address) {
  const balance = await provider.getBalance(address);
  return ethers.formatEther(balance);
}

export async function estimateEthTransfer(fromWalletIndex, to, amountEth) {
  const wallet = getWallet(fromWalletIndex);
  const tx = {
    from: wallet.address,
    to,
    value: ethers.parseEther(String(amountEth)),
  };
  const gasLimit = await provider.estimateGas(tx);
  const feeData = await provider.getFeeData();
  return {
    gasLimit: gasLimit.toString(),
    gasPrice: feeData.gasPrice ? feeData.gasPrice.toString() : null,
    maxFeePerGas: feeData.maxFeePerGas ? feeData.maxFeePerGas.toString() : null,
    maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? feeData.maxPriorityFeePerGas.toString() : null,
  };
}

export async function sendEth(fromWalletIndex, to, amountEth, options = {}) {
  const wallet = getWallet(fromWalletIndex);
  const feeData = await provider.getFeeData();

  const tx = {
    to,
    value: ethers.parseEther(String(amountEth)),
  };

  if (options.gasLimit) {
    tx.gasLimit = BigInt(options.gasLimit);
  } else {
    tx.gasLimit = await provider.estimateGas({
      from: wallet.address,
      to,
      value: tx.value,
    });
  }

  if (options.nonce !== undefined) {
    tx.nonce = options.nonce;
  }

  if (options.gasPrice) {
    tx.gasPrice = BigInt(options.gasPrice);
  } else if (options.maxFeePerGas || options.maxPriorityFeePerGas) {
    tx.maxFeePerGas = options.maxFeePerGas
      ? BigInt(options.maxFeePerGas)
      : feeData.maxFeePerGas || undefined;
    tx.maxPriorityFeePerGas = options.maxPriorityFeePerGas
      ? BigInt(options.maxPriorityFeePerGas)
      : feeData.maxPriorityFeePerGas || undefined;
  } else if (feeData.maxFeePerGas && feeData.maxPriorityFeePerGas) {
    tx.maxFeePerGas = feeData.maxFeePerGas;
    tx.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;
  } else if (feeData.gasPrice) {
    tx.gasPrice = feeData.gasPrice;
  }

  const response = await wallet.sendTransaction(tx);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    nonce: response.nonce,
    gasLimit: response.gasLimit?.toString(),
    blockNumber: receipt?.blockNumber ?? null,
    status: receipt?.status ?? null,
  };
}

export function getContract(contractAddress, abi, walletIndex = 0) {
  const wallet = getWallet(walletIndex);
  return new ethers.Contract(contractAddress, abi, wallet);
}

export async function callContractRead(contractAddress, abi, method, args = []) {
  const contract = new ethers.Contract(contractAddress, abi, provider);
  if (typeof contract[method] !== "function") {
    throw new Error(`Read method "${method}" not found on contract`);
  }
  const result = await contract[method](...args);
  return result;
}

export async function estimateContractWrite(contractAddress, abi, walletIndex, method, args = [], overrides = {}) {
  const contract = getContract(contractAddress, abi, walletIndex);

  if (!contract[method]) {
    throw new Error(`Write method "${method}" not found on contract`);
  }

  const populated = await contract[method].populateTransaction(...args, overrides);
  const wallet = getWallet(walletIndex);

  const gasLimit = await provider.estimateGas({
    from: wallet.address,
    to: contractAddress,
    data: populated.data,
    value: populated.value || 0n,
  });

  const feeData = await provider.getFeeData();

  return {
    gasLimit: gasLimit.toString(),
    gasPrice: feeData.gasPrice ? feeData.gasPrice.toString() : null,
    maxFeePerGas: feeData.maxFeePerGas ? feeData.maxFeePerGas.toString() : null,
    maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? feeData.maxPriorityFeePerGas.toString() : null,
  };
}

export async function sendContractTransaction(
  contractAddress,
  abi,
  walletIndex,
  method,
  args = [],
  overrides = {}
) {
  const contract = getContract(contractAddress, abi, walletIndex);

  if (typeof contract[method] !== "function") {
    throw new Error(`Write method "${method}" not found on contract`);
  }

  const txResponse = await contract[method](...args, overrides);
  const receipt = await txResponse.wait();

  return {
    hash: txResponse.hash,
    from: txResponse.from,
    to: txResponse.to,
    nonce: txResponse.nonce,
    blockNumber: receipt?.blockNumber ?? null,
    status: receipt?.status ?? null,
    gasUsed: receipt?.gasUsed?.toString?.() ?? null,
  };
}

export async function getTransaction(hash) {
  const tx = await provider.getTransaction(hash);
  if (!tx) return null;
  return {
    hash: tx.hash,
    from: tx.from,
    to: tx.to,
    nonce: tx.nonce,
    value: tx.value?.toString?.(),
    blockNumber: tx.blockNumber,
  };
}

export async function getTransactionReceipt(hash) {
  const receipt = await provider.getTransactionReceipt(hash);
  if (!receipt) return null;
  return {
    hash,
    blockNumber: receipt.blockNumber,
    status: receipt.status,
    gasUsed: receipt.gasUsed?.toString?.(),
    contractAddress: receipt.contractAddress,
  };
}

export async function waitForTransaction(hash, confirmations = 1, timeout = 0) {
  const receipt = await provider.waitForTransaction(hash, confirmations, timeout);
  return receipt;
}

export async function getCurrentBlockNumber() {
  return await provider.getBlockNumber();
}

export async function getNetwork() {
  return await provider.getNetwork();
}

export const erc20Abi = [
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function totalSupply() view returns (uint256)",
  "function balanceOf(address owner) view returns (uint256)",
  "function transfer(address to, uint256 amount) returns (bool)",
  "function allowance(address owner, address spender) view returns (uint256)",
  "function approve(address spender, uint256 amount) returns (bool)",
  "function transferFrom(address from, address to, uint256 amount) returns (bool)",
];

export async function getErc20Balance(tokenAddress, ownerAddress) {
  const contract = new ethers.Contract(tokenAddress, erc20Abi, provider);
  const [balance, decimals, symbol] = await Promise.all([
    contract.balanceOf(ownerAddress),
    contract.decimals(),
    contract.symbol(),
  ]);

  return {
    raw: balance.toString(),
    formatted: ethers.formatUnits(balance, decimals),
    decimals: Number(decimals),
    symbol,
  };
}

export async function sendErc20(tokenAddress, walletIndex, to, amount, decimalsOverride) {
  const wallet = getWallet(walletIndex);
  const contract = new ethers.Contract(tokenAddress, erc20Abi, wallet);
  const decimals = decimalsOverride ?? (await contract.decimals());
  const parsedAmount = ethers.parseUnits(String(amount), decimals);

  const txResponse = await contract.transfer(to, parsedAmount);
  const receipt = await txResponse.wait();

  return {
    hash: txResponse.hash,
    from: txResponse.from,
    to: txResponse.to,
    nonce: txResponse.nonce,
    blockNumber: receipt?.blockNumber ?? null,
    status: receipt?.status ?? null,
    gasUsed: receipt?.gasUsed?.toString?.() ?? null,
  };
}

